SELECT w.work_id, w.user_id, w.work_title, w.img_url, w.series_id, w.like_count, w.star_count, w.view_count, w.is_original_work, w.out_url, w.update_time, w.update_user, w.create_time, w.create_user FROM tb_works w WHERE w.is_delete = 0 AND w.approval_status = 10
AND w.work_title LIKE CONCAT('%', #{workTitle}, '%')
AND w.user_id = #{userId}
AND w.series_id = #{seriesId}
AND w.is_original_work = #{isOriginal}
ORDER BY w.create_time DESC

