SELECT (IFNULL(h.cnt, 0) + IFNULL(g.cnt, 0)) AS count
FROM (
    SELECT COUNT(*) AS cnt FROM tb_history WHERE work_id = #{workId}
) h,
(
    SELECT COUNT(*) AS cnt FROM tb_guest_history WHERE work_id = #{workId}
) g
